const API_URL="http://localhost:3000/entregas",ITEMS_PER_PAGE=10;let entregasCompletas=[],paginaAtual=1,entregasFiltradas=[];function toggleMenu(){document.getElementById("hamburger").classList.toggle("active"),document.getElementById("navMenu").classList.toggle("active")}function closeMenu(){document.getElementById("hamburger").classList.remove("active"),document.getElementById("navMenu").classList.remove("active")}document.getElementById("hamburger")?.addEventListener("click",toggleMenu),document.querySelectorAll(".nav-link").forEach(e=>{e.addEventListener("click",closeMenu)});function showLoader(e=!0){document.getElementById("loader").classList.toggle("active",e)}async function initDashboard(){showLoader(!0);try{const e=await fetch(API_URL);if(!e.ok)throw new Error("Erro ao carregar dados");entregasCompletas=await e.json(),entregasFiltradas=[...entregasCompletas],paginaAtual=1,renderizarDashboard(),calcularInsights(entregasCompletas),setupFiltro(),setupPaginacao()}catch(e){console.error("Falha na API:",e),document.getElementById("corpo-tabela").innerHTML='<tr><td colspan="6" style="text-align:center; color:#dc2626">⚠️ Erro ao carregar dados da API</td></tr>'}finally{showLoader(!1)}}function renderizarDashboard(){const e=document.getElementById("corpo-tabela"),a=document.getElementById("kpi-atraso"),t=document.getElementById("kpi-total"),r=document.getElementById("kpi-dentro-prazo"),o=document.getElementById("kpi-atrasadas"),d=entregasCompletas.length,s=entregasCompletas.filter(e=>e.real>e.prazo);let i=d>0?Math.round(s.length/d*100):0;t.textContent=d,a.textContent=i+"%",a.style.color=i>50?"#dc2626":"#059669",r.textContent=d-s.length,o.textContent=s.length;const l=(paginaAtual-1)*ITEMS_PER_PAGE,c=l+ITEMS_PER_PAGE,b=entregasFiltradas.slice(l,c);e.innerHTML=b.map((e,a)=>{const t=e.real>e.prazo,r=Math.abs(e.real-e.prazo);return`<tr style="animation-delay: ${.05*a}s" tabindex="0"><td>#${e.id}</td><td>${e.transportadora}</td><td>${e.regiao}</td><td>${e.prazo} dias</td><td>${e.real} dias</td><td><span class="status-pill ${t?"atrasado":"ok"}" title="${t?`+${r} dias atrasado`:`${r} dias adiantado`}">${t?"Atrasado":"No Prazo"}</span></td></tr>`}).join(""),0===b.length&&(e.innerHTML='<tr><td colspan="6" style="text-align:center; color:#475569; padding: 2rem;">Nenhum resultado encontrado</td></tr>'),atualizarPaginacao()}function calcularInsights(e){if(0!==e.length){const a=e.reduce((e,a)=>Math.abs(e.real-e.prazo)<Math.abs(a.real-a.prazo)?e:a);document.getElementById("best-performer").textContent=a.transportadora,document.getElementById("best-detail").textContent=`${a.regiao} • ${Math.abs(a.real-a.prazo)} dias`;const t=e.reduce((e,a)=>a.real-a.prazo>e.real-e.prazo?a:e);document.getElementById("worst-performer").textContent=t.transportadora,document.getElementById("worst-detail").textContent=`${t.regiao} • +${t.real-t.prazo} dias`;const r={};e.forEach(e=>{r[e.regiao]||(r[e.regiao]={total:0,atrasadas:0}),r[e.regiao].total++,e.real>e.prazo&&r[e.regiao].atrasadas++});const o=Object.entries(r).reduce((e,a)=>(a[1].atrasadas/a[1].total||0)>(e[1].atrasadas/e[1].total||0)?a:e),d=Math.round(o[1].atrasadas/o[1].total*100);document.getElementById("critical-region").textContent=o[0],document.getElementById("region-detail").textContent=d+"% de atraso"}}function setupFiltro(){document.getElementById("filtro-busca").addEventListener("input",e=>{const a=e.target.value.toLowerCase();paginaAtual=1,entregasFiltradas=entregasCompletas.filter(e=>e.transportadora.toLowerCase().includes(a)||e.regiao.toLowerCase().includes(a)||e.id.toString().includes(a)),renderizarDashboard()})}function setupPaginacao(){document.getElementById("prev-btn").addEventListener("click",()=>{paginaAtual>1&&(paginaAtual--,renderizarDashboard(),document.querySelector("table").focus())}),document.getElementById("next-btn").addEventListener("click",()=>{Math.ceil(entregasFiltradas.length/10)>paginaAtual&&(paginaAtual++,renderizarDashboard(),document.querySelector("table").focus())})}function atualizarPaginacao(){const e=Math.ceil(entregasFiltradas.length/10),a=document.getElementById("prev-btn"),t=document.getElementById("next-btn"),r=document.getElementById("pag-info");a.disabled=1===paginaAtual,t.disabled=paginaAtual===e,r.textContent=`Página ${paginaAtual} de ${e} (${entregasFiltradas.length} resultados)`}document.addEventListener("DOMContentLoaded",initDashboard);